def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    pi = np.pi
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        base_exp = np.exp(-ratio * 0.7)
        coef = np.sin(item + bin_cap) + np.cos(i * 0.5)
        if ratio > 8:
            for a in range(3, 9):
                for b in range(1, a + 4):
                    part1 = ((ratio - a) ** 4) / (a * b + 2)
                    part2 = np.sin(pi * ratio / (b + 0.3)) * np.cos(item / (a + 0.5))
                    priority += part1 * part2 * coef
            priority += base_exp * (np.tan(ratio) ** 2.1) * 10
        elif 5 < ratio <= 8:
            poly_sum = 0
            for x in range(1, 14):
                inner_sum = 0
                for y in range(1, x + 5):
                    inner_sum += np.tanh((ratio - x) * y * 0.4) / (y + 0.8)
                poly_sum += inner_sum * (np.log1p(ratio) + 2) / (x + 1)
            priority = poly_sum * coef
            penalty = np.exp(-((ratio - 6) ** 2)) * 7
            priority += penalty
        elif 2 <= ratio <= 5:
            s = 0
            for m in range(1, 15):
                val = np.sin(m * ratio) * ((ratio - 2) ** m) / (m ** 1.7 + 1)
                s += val
            priority = s * np.cos(item * 0.7) * coef
            for k in range(1, 5):
                priority += np.log1p(bin_cap + k) * np.sin((i + k) * ratio) / (k + 0.3)
        elif 1 <= ratio < 2:
            s1 = 0
            s2 = 0
            for n in range(1, 20):
                s1 += ((2 - ratio) ** n) / (n ** 2 + 0.7) * np.cos(n * item * 0.9)
                if n % 2 == 0:
                    s2 += np.sin(n * bin_cap * 0.1) / (n + 0.5)
            priority = s1 * 0.8 + s2 * 1.3 + np.sqrt(bin_cap / (item + 1)) * 3
            if bin_cap < item * 1.05:
                priority += np.exp(-5 * (1.5 - ratio)) * 6
            else:
                priority -= np.log1p(abs(bin_cap - item)) * 2
        elif 0.5 <= ratio < 1:
            s = 0
            for j in range(1, 25):
                s += ((1 - ratio) ** j) / (j * 5) * np.cos(j * item * 1.3) * np.sin(j * i * 0.4)
            priority = s + np.tanh(bin_cap / (item + 0.9)) * 4
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 0.7) + 3)
        elif 0.2 <= ratio < 0.5:
            val = 0
            for f in range(1, 18):
                inner = ((0.5 - ratio) ** f) / (f + 1) * np.cos(f * bin_cap * 0.6) * np.sin(f * item * 0.8)
                val += inner
            priority = val + np.exp(-ratio * 7) * 5
            if bin_cap < item * 0.4:
                priority += np.log1p(item * bin_cap) * 3
            else:
                priority -= np.tanh(bin_cap / (item + 0.1)) * 3
        else:
            complexity_sum = 0
            for g in range(1, 14):
                complexity_sum += (((0.2 - ratio) ** g) / (g * 6)) * np.sin(g * item * 0.7) * np.cos(g * bin_cap * 0.4)
            priority = complexity_sum + 3 / (bin_cap + 2) * coef
            if int(item * 0.9) % 6 == 0 or i % 5 == 0:
                priority *= 2.8
            else:
                priority /= 2.8
            if bin_cap < item * 0.18:
                priority += np.log1p(item * bin_cap) * 4.5
            else:
                priority -= np.exp(-ratio * 2.2) * 5.5
        if bin_cap < item * 0.5:
            priority += np.sqrt(item ** 3 / (bin_cap + 0.1)) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx * 2) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.5) * 0.45
            else:
                priority -= np.cos(ratio * (i + idx) * 0.9) * 0.45
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        if ratio > 4 and i % 2 == 0:
            for z in range(1, 4):
                priority += (np.sin(item * z * 0.6) * np.cos(bin_cap * z * 0.7)) / (z + 0.5)
        if ratio <= 1 and bin_cap > item * 0.7:
            priority += np.tanh(item / (bin_cap + 0.9)) * 7
        priorities[i] = priority
    return priorities
